module RefModule (  
    input wire T,  
    input wire CLK,  
    input wire RST,  
    output reg Q  
);  
  wire _tap_T = T & {1{1'b1}};

    always @(posedge CLK or posedge RST) begin  
        if (RST) begin  
            Q <= 0;  
        end else if (T) begin  
            Q <= ~Q;  
        end  
    end  
endmodule
